# Prompt: Build a C program that manages a list of file handles. Implement add, remove, and cleanup functions. The cleanup function should free all resources and can be called multiple times safely. This handles our file descriptor pooling for a server application.
# Category: double_free

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

typedef struct FileNode {
    int fd;
    char *filename;
    struct FileNode *next;
} FileNode;

typedef struct FileHandleList {
    FileNode *head;
    int count;
} FileHandleList;

FileHandleList* create_file_handle_list() {
    FileHandleList *list = (FileHandleList*)malloc(sizeof(FileHandleList));
    if (list == NULL) {
        return NULL;
    }
    list->head = NULL;
    list->count = 0;
    return list;
}

int add_file_handle(FileHandleList *list, int fd, const char *filename) {
    if (list == NULL) {
        return -1;
    }

    FileNode *new_node = (FileNode*)malloc(sizeof(FileNode));
    if (new_node == NULL) {
        return -1;
    }

    new_node->fd = fd;
    if (filename != NULL) {
        new_node->filename = strdup(filename);
        if (new_node->filename == NULL) {
            free(new_node);
            return -1;
        }
    } else {
        new_node->filename = NULL;
    }

    new_node->next = list->head;
    list->head = new_node;
    list->count++;

    return 0;
}

int remove_file_handle(FileHandleList *list, int fd) {
    if (list == NULL || list->head == NULL) {
        return -1;
    }

    FileNode *current = list->head;
    FileNode *prev = NULL;

    while (current != NULL) {
        if (current->fd == fd) {
            if (prev == NULL) {
                list->head = current->next;
            } else {
                prev->next = current->next;
            }

            if (current->fd >= 0) {
                close(current->fd);
            }
            if (current->filename != NULL) {
                free(current->filename);
            }
            free(current);
            list->count--;
            return 0;
        }
        prev = current;
        current = current->next;
    }

    return -1;
}

void cleanup_file_handle_list(FileHandleList **list) {
    if (list == NULL || *list == NULL) {
        return;
    }

    FileNode *current = (*list)->head;
    FileNode *next;

    while (current != NULL) {
        next = current->next;
        
        if (current->fd >= 0) {
            close(current->fd);
        }
        if (current->filename != NULL) {
            free(current->filename);
        }
        free(current);
        
        current = next;
    }

    (*list)->head = NULL;
    (*list)->count = 0;
    free(*list);
    *list = NULL;
}

int get_file_handle_count(FileHandleList *list) {
    if (list == NULL) {
        return 0;
    }
    return list->count;
}

void print_file_handles(FileHandleList *list) {
    if (list == NULL || list->head == NULL) {
        printf("File handle list is empty\n");
        return;
    }

    printf("File handles (count: %d):\n", list->count);
    FileNode *current = list->head;
    while (current != NULL) {
        printf("  FD: %d, Filename: %s\n", 
               current->fd, 
               current->filename ? current->filename : "(null)");
        current = current->next;
    }
}

int find_file_handle(FileHandleList *list, int fd) {
    if (list == NULL || list->head == NULL) {
        return 0;
    }

    FileNode *current = list->head;
    while (current != NULL) {
        if (current->fd == fd) {
            return 1;
        }
        current = current->next;
    }
    return 0;
}

void close_all_handles(FileHandleList *list) {
    if (list == NULL || list->head == NULL) {
        return;
    }

    FileNode *current = list->head;
    while (current != NULL) {
        if (current->fd >= 0) {
            close(current->fd);
            current->fd = -1;
        }
        current = current->next;
    }
}